        return []
    sieve = [True] * (n + 1)
    sieve[0] = sieve[1] = False
    i = 2
    while i * i <= n:
        if sieve[i]:
            for j in range(i * i, n + 1, i):
                sieve[j] = False
        i += 1
    return [k for k in range(n + 1) if sieve[k]]

def gcd(a, b):
    a, b = abs(a), abs(b)
    while b:
        a, b = b, a % b
    return a

def lcm(a, b):
    if a == 0 or b == 0:
        return 0
    x, y = abs(a), abs(b)
    g, r = x, y
    while r:
        g, r = r, g % r
    return x * y // g

def digit_product(n):
    n = abs(n)
    if n == 0:
        return 0
    product = 1
    while n > 0:
        product *= n % 10
        n //= 10
    return product

def is_palindrome_number(n):
    if n < 0:
        return False
    original = n
    reversed_n = 0
    while n > 0:
        reversed_n = reversed_n * 10 + n % 10
        n //= 10
    return original == reversed_n

def is_armstrong(n):
    if n < 0:
        return False
    digits = str(n)
    power = len(digits)
    return n == sum(int(d) ** power for d in digits)

def is_perfect(n):
    if n < 2:
        return False
    total = 1
    i = 2
    while i * i <= n:
        if n % i == 0:
            total += i
            if i != n // i:
                total += n // i
        i += 1
    return total == n

def power(base, exp):
    if exp == 0:
        return 1
    if exp < 0:
        return 1 / power(base, -exp)
    result = 1
    for _ in range(exp):
        result *= base
    return result

def int_sqrt(n):
    if n < 0:
        raise ValueError("square root of negative number")
    if n < 2:
        return n
    low, high = 1, n
    while low <= high:
        mid = (low + high) // 2
        if mid * mid <= n:
            low = mid + 1
        else:
            high = mid - 1
    return high

def to_binary(n):
    if n == 0:
        return "0"
    sign = "-" if n < 0 else ""
    n = abs(n)
    bits = ""
    while n > 0:
        bits = str(n % 2) + bits
        n //= 2
    return sign + bits

def from_binary(s):
    s = s.strip()
    sign = 1
    if s.startswith("-"):
        sign = -1
        s = s[1:]
    value = 0
    for ch in s:
        value = value * 2 + int(ch)
    return sign * value

def from_hex(s):
    s = s.strip().lower()
    sign = 1
    if s.startswith("-"):
        sign = -1
        s = s[1:]
    if s.startswith("0x"):
        s = s[2:]
    digits = "0123456789abcdef"
    value = 0
    for ch in s:
        value = value * 16 + digits.index(ch)
    return sign * value

def to_base(n, base):
    if base < 2 or base > 16:
        raise ValueError("base must be between 2 and 16")
    if n == 0:
        return "0"
    digits = "0123456789ABCDEF"
    sign = "-" if n < 0 else ""
    n = abs(n)
    out = ""
    while n > 0:
        out = digits[n % base] + out
        n //= base
    return sign + out

def discounted_price(price, discount_percent):
    final = price * (1 - discount_percent / 100.0)
    return "{:.2f}".format(final)

def price_with_tax(price, tax_percent):
    final = price * (1 + tax_percent / 100.0)
    return "{:.2f}".format(final)

def percent_change(old, new):
    if old == 0:
        raise ValueError("old value must be non-zero")
    return round((new - old) / old * 100.0, 2)

def compound_interest(principal, rate_percent, years, compounds_per_year=1):
    rate = rate_percent / (100.0 * compounds_per_year)
    periods = compounds_per_year * years
    amount = principal * (1 + rate) ** periods
    return round(amount, 2)

def simple_interest(principal, rate_percent, years):
    interest = principal * rate_percent * years / 100.0
    return round(interest, 2)

def average(numbers):
    if not numbers:
        return 0.0
    return sum(numbers) / len(numbers)

def median(numbers):
    if not numbers:
        raise ValueError("median of empty list")
    s = sorted(numbers)
    n = len(s)
    mid = n // 2
    if n % 2 == 1:
        return s[mid]
    return (s[mid - 1] + s[mid]) / 2

def mode(numbers):
    if not numbers:
        raise ValueError("mode of empty list")
    counts = {}
    for x in numbers:
        counts[x] = counts.get(x, 0) + 1
    best_count = max(counts.values())
    return min(x for x in counts if counts[x] == best_count)

def clamp(value, low, high):
    if low > high:
        raise ValueError("low must not exceed high")
    if value < low:
        return low
    if value > high:
        return high
    return value

def convert_temperature(value, from_unit, to_unit):
    from_unit = from_unit.upper()[0]
    to_unit = to_unit.upper()[0]
    if from_unit == "F":
        c = (value - 32) * 5.0 / 9.0
    elif from_unit == "K":
        c = value - 273.15
    else:
        c = value
    if to_unit == "F":
        out = c * 9.0 / 5.0 + 32
    elif to_unit == "K":
        out = c + 273.15
    else:
        out = c
    return round(out, 2)

def collatz_steps(n):
    if n < 1:
        raise ValueError("n must be a positive integer")
    steps = 0
    while n != 1:
        if n % 2 == 0:
            n //= 2
        else:
            n = 3 * n + 1
        steps += 1
    return steps

def sum_of_multiples(n):
    total = 0
    for i in range(n):
        if i % 3 == 0 or i % 5 == 0:
            total += i
    return total

def is_valid_triangle(a, b, c):
    if a <= 0 or b <= 0 or c <= 0:
        return False
    return a + b > c and a + c > b and b + c > a

def quadratic_roots(a, b, c):
    if a == 0:
        raise ValueError("not a quadratic equation (a is 0)")
    disc = b * b - 4 * a * c
    if disc < 0:
        return []
    if disc == 0:
        return [-b / (2 * a)]
    root = disc ** 0.5
    r1 = (-b - root) / (2 * a)
    r2 = (-b + root) / (2 * a)
    return sorted([r1, r2])

def round_to_step(value, step):
    if step <= 0:
        raise ValueError("step must be positive")
    q = value / step
    if q >= 0:
        n = int(q + 0.5)
    else:
        n = -int(-q + 0.5)
    return n * step

def prime_factors(n):
    if n < 2:
        return []
    factors = []
    d = 2
    while d * d <= n:
        while n % d == 0:
            factors.append(d)
            n //= d
        d += 1
    if n > 1:
        factors.append(n)
    return factors

def count_digits(n):
    n = abs(n)
    if n == 0:
        return 1
    count = 0
    while n > 0:
        count += 1
        n //= 10
    return count

def digital_root(n):
    n = abs(n)
    while n >= 10:
        total = 0
        while n > 0:
            total += n % 10
            n //= 10
        n = total
    return n

def divisors(n):
    if n < 1:
        return []
    small = []
    large = []
    i = 1
    while i * i <= n:
        if n % i == 0:
            small.append(i)
            if i != n // i:
                large.append(n // i)
        i += 1
    return small + large[::-1]

def nth_prime(n):
    if n < 1:
        raise ValueError("n must be at least 1")
    count = 0
    candidate = 1
    while count < n:
        candidate += 1
        is_p = candidate >= 2
        i = 2
        while i * i <= candidate:
            if candidate % i == 0:
                is_p = False
                break
            i += 1
        if is_p:
            count += 1
    return candidate

