def flatten_dict(d, parent_key=""):
    flat = {}
    for k, v in d.items():
        new_key = parent_key + "." + str(k) if parent_key else str(k)
        if isinstance(v, dict) and v:
            flat.update(flatten_dict(v, new_key))
        else:
            flat[new_key] = v
    return flat

def is_valid_date(s):
    if not isinstance(s, str) or len(s) != 10 or s[4] != "-" or s[7] != "-":
        return False
    y_part, m_part, d_part = s[0:4], s[5:7], s[8:10]
    if not (y_part.isdigit() and m_part.isdigit() and d_part.isdigit()):
        return False
    y, m, d = int(y_part), int(m_part), int(d_part)
    if m < 1 or m > 12 or d < 1:
        return False
    month_days = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
    limit = month_days[m - 1]
    if m == 2 and y % 4 == 0 and (y % 100 != 0 or y % 400 == 0):
        limit = 29
    return d <= limit

